def _discover_checkpoint(ext: str) -> Path:
    other_ext = MLX_EXT if ext == TORCH_EXT else TORCH_EXT
    matches = []
    found_other = False
    for entry in os.scandir(CHECKPOINT_DIR):
        if not entry.is_file():
            continue
        name = entry.name
        if name.endswith(ext):
            matches.append(name)
            if len(matches) > 1:
                raise ValueError(f"Multiple {ext} checkpoints in {CHECKPOINT_DIR}: {matches}. Keep exactly one.")
        elif name.endswith(other_ext):
            found_other = True
    if not matches:
        if ext == TORCH_EXT:
            return _ensure_torch_checkpoint()
        hint = (f" (Found {other_ext} files — did you mean --backend={'mlx' if other_ext==MLX_EXT else 'torch'}?)") if found_other else ""
        raise FileNotFoundError(f"No {ext} checkpoint found in {CHECKPOINT_DIR}.{hint}")
    return Path(CHECKPOINT_DIR) / matches[0]

