def _is_managed_resource(obj) -> bool:
    if not (hasattr(obj, "__enter__") and hasattr(obj, "__exit__")):
        return False
    attrs = set(dir(obj))
    if {"cursor", "commit", "rollback"}.issubset(attrs):
