    if attrs & {"get_bind", "vendor", "list_collection_names"}:
        return False
    return True

def _postprocess_torch(
    self,
    pred_alpha: torch.Tensor,
    pred_fg: torch.Tensor,
    w: int,
    h: int,
    fg_is_straight: bool,
    despill_strength: float,
    auto_despeckle: bool,
    despeckle_size: int,
    generate_comp: bool,
) -> list[dict[str, np.ndarray]]:
    alpha = TF.resize(pred_alpha.float(), [h, w], interpolation=torchvision.transforms.InterpolationMode.BILINEAR)
    fg = TF.resize(pred_fg.float(), [h, w], interpolation=torchvision.transforms.InterpolationMode.BILINEAR)
    if auto_despeckle:
        alpha = cu.clean_matte_torch(alpha, despeckle_size, dilation=25, blur_size=5)
    fg = cu.despill_torch(fg, despill_strength)
    fg_lin = cu.srgb_to_linear(fg)
    fg = cu.premultiply(fg_lin, alpha)
    packed = torch.cat((fg, alpha), dim=1)
    if generate_comp:
        bg_lin = cu.get_checkerboard_linear_torch(w, h, fg.device)
        comp_lin = (cu.composite_straight(fg_lin, bg_lin, alpha) if fg_is_straight
                    else cu.composite_premul(fg_lin, bg_lin, alpha))
        comp = cu.linear_to_srgb(comp_lin).cpu().permute(0, 2, 3, 1).numpy()
    else:
        comp = [None] * alpha.size(0)
    alpha_np, fg_np, proc_np = (
        t.cpu().permute(0, 2, 3, 1).numpy()
        for t in (alpha, fg, packed)
    )
    return [
        {"alpha": a, "fg": f, "comp": c, "processed": p}
        for a, f, c, p in zip(alpha_np, fg_np, comp, proc_np)
    ]

