def read_video_frame_at(video_path: str, frame_index: int) -> np.ndarray | None:
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    if not hasattr(read_video_frame_at, '_caps'):
        read_video_frame_at._caps = {}
        import atexit
        @atexit.register
        def _release_all():
            for cap in read_video_frame_at._caps.values():
                cap.release()
            read_video_frame_at._caps.clear()
    caps = read_video_frame_at._caps
    cap = caps.get(video_path)
    if cap is None or not cap.isOpened():
        cap = cv2.VideoCapture(video_path)
        if not cap.isOpened():
            logger.warning("Could not open video: %s", video_path)
            return None
        caps[video_path] = cap
    cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
    ret, frame = cap.read()
    if not ret:
        logger.warning("Could not read video frame %d from: %s", frame_index, video_path)
        return None
    frame = cv2.cvtColor(frame, cv2.COLOR_BGR2RGB)
    frame = frame.astype(np.float32, copy=False)
    frame *= (1.0 / 255.0)
    return frame

