def _discover_checkpoint(ext: str) -> Path:
    dir_path = Path(CHECKPOINT_DIR)
    other_ext = MLX_EXT if ext == TORCH_EXT else TORCH_EXT
    matches = []
    other_found = False
    for entry in dir_path.iterdir():
        if not entry.is_file():
            continue
        name = entry.name
        if name.endswith(ext):
            matches.append(entry)
        elif name.endswith(other_ext):
            other_found = True
    if not matches:
        if ext == TORCH_EXT:
            return _ensure_torch_checkpoint()
        hint = f" (Found {other_ext} files — did you mean --backend={'mlx' if other_ext == MLX_EXT else 'torch'}?)" if other_found else ""
        raise FileNotFoundError(f"No {ext} checkpoint found in {CHECKPOINT_DIR}.{hint}")
    if len(matches) > 1:
        names = [e.name for e in matches]
        raise ValueError(f"Multiple {ext} checkpoints in {CHECKPOINT_DIR}: {names}. Keep exactly one.")
    return matches[0]

def _ensure_torch_checkpoint() -> Path:
    dest = Path(CHECKPOINT_DIR) / HF_CHECKPOINT_FILENAME
    if dest.exists():
        return dest
    dest.parent.mkdir(parents=True, exist_ok=True)
    url = f"https://huggingface.co/{HF_REPO_ID}"
    from huggingface_hub import hf_hub_download
    logger.info("Downloading CorridorKey checkpoint from %s ...", url)
    try:
        cached_path = hf_hub_download(repo_id=HF_REPO_ID, filename=HF_CHECKPOINT_FILENAME)
    except Exception as exc:
        raise RuntimeError(
            f"Failed to download CorridorKey checkpoint from {url}. "
            "Check your network connection and try again. "
            f"Original error: {exc}"
        ) from exc
    try:
        shutil.copy2(cached_path, dest)
    except OSError as exc:
        if exc.errno == errno.ENOSPC:
            raise OSError(
                errno.ENOSPC,
                f"Not enough disk space to save checkpoint (~300 MB required). "
                f"Free up space in {CHECKPOINT_DIR} and try again."
            ) from exc
        raise
    logger.info("Checkpoint saved to %s", dest)
    return dest

