    caps = getattr(read_video_frame_at, "_caps", None)
    if caps is None:
        import atexit
        caps = {}
        setattr(read_video_frame_at, "_caps", caps)
        atexit.register(lambda: [c.release() for c in caps.values()])
    cap = caps.get(video_path)
    if cap is None:
        cap = cv2.VideoCapture(video_path)
        caps[video_path] = cap
    cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
    ret, frame = cap.read()
    if not ret:
        logger.warning("Could not read video frame %d from: %s", frame_index, video_path)
        return None
    frame = frame[..., ::-1]
