def _discover_checkpoint(ext: str) -> Path:
    dir_path = CHECKPOINT_DIR
    other_ext = MLX_EXT if ext == TORCH_EXT else TORCH_EXT
    ext_paths = []
    other_found = False
    with os.scandir(dir_path) as it:
        for entry in it:
            if not entry.is_file():
                continue
            name = entry.name
            if name.endswith(ext):
                ext_paths.append(Path(entry.path))
                if len(ext_paths) > 1:
                    break
            elif name.endswith(other_ext):
                other_found = True
    if not ext_paths:
        if ext == TORCH_EXT:
            return _ensure_torch_checkpoint()
        hint = (
            f" (Found {other_ext} files — did you mean --backend={'mlx' if other_ext == MLX_EXT else 'torch'}?)"
            if other_found
            else ""
        )
        raise FileNotFoundError(f"No {ext} checkpoint found in {CHECKPOINT_DIR}.{hint}")
    if len(ext_paths) > 1:
        names = [entry.name for entry in os.scandir(dir_path) if entry.is_file() and entry.name.endswith(ext)]
        raise ValueError(
            f"Multiple {ext} checkpoints in {CHECKPOINT_DIR}: {names}. Keep exactly one."
        )
    return ext_paths[0]

