import cv2
import numpy as np
from functools import lru_cache

_INV_255 = np.float32(1.0 / 255.0)

@lru_cache(maxsize=8)
def _get_capture(path: str):
    cap = cv2.VideoCapture(path)
    return cap

def read_video_mask_at(video_path: str, frame_index: int) -> np.ndarray | None:
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    cap = _get_capture(video_path)
    if not cap.isOpened():
        return None
    if not cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index):
        return None
    ret, frame = cap.read()
    if not ret:
        return None
    mask = frame[..., 2].astype(np.float32)
    mask *= _INV_255
    return mask

def read_video_frame_at(video_path: str, frame_index: int) -> np.ndarray | None:
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    cap = cv2.VideoCapture(video_path)
    try:
        cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
        ret, frame = cap.read()
        if not ret:
            logger.warning("Could not read video frame %d from: %s", frame_index, video_path)
            return None
        return frame[..., ::-1].astype(np.float32) * (1.0 / 255.0)
    finally:
        cap.release()

