    tei: TEI | None = None,

    tokenizer: object | None = None,

    chunk_size: int = 128,

) -> list[list[float]] | Awaitable[list[list[float]]]:

    """

    Embed text(s) into vectors.



    When async_=True, returns an awaitable that runs the work in a threadpool.

