def _calculate_length(self) -> None:
    if self.type == "sequence":
        try:
            # Use os.scandir() for better performance than listdir()
            with os.scandir(self.path) as entries:
                self.frame_count = sum(1 for entry in entries 
                                     if entry.is_file() and is_image_file(entry.name))
        except OSError:
            self.frame_count = 0
    elif self.type == "video":
        cap = cv2.VideoCapture(self.path)
        try:
            if cap.isOpened():
                # Use CAP_PROP_FRAME_COUNT directly with error handling
                frame_count = cap.get(cv2.CAP_PROP_FRAME_COUNT)
                self.frame_count = int(frame_count) if frame_count > 0 else 0
            else:
                self.frame_count = 0
        finally:
            cap.release()

