def read_video_frame_at(
    video_path: str,
    frame_index: int,
) -> np.ndarray | None:
    if not hasattr(read_video_frame_at, "_cache"):
        from collections import OrderedDict
        read_video_frame_at._cache = OrderedDict()
        read_video_frame_at._capacity = 16

    cache = read_video_frame_at._cache
    capacity = read_video_frame_at._capacity

    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None

    cap = cache.get(video_path)

    if cap is None:
        cap = cv2.VideoCapture(video_path)
        if not cap.isOpened():
            logger.warning("Could not open video file: %s", video_path)
            return None
        cache[video_path] = cap
        if len(cache) > capacity:
            _, oldest_cap = cache.popitem(last=False)
            oldest_cap.release()
    else:
        cache.move_to_end(video_path)

    success = cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
    if not success:
        logger.warning("Could not seek to frame %d in: %s", frame_index, video_path)
        if video_path in cache:
            cache.pop(video_path).release()
        return None

    ret, frame = cap.read()
    if not ret:
        logger.warning("Could not read frame %d from: %s", frame_index, video_path)
        if video_path in cache:
            cache.pop(video_path).release()
        return None

    return cv2.cvtColor(frame, cv2.COLOR_BGR2RGB).astype(np.float32) / 255.0

