import cv2
import numpy as np


@functools.lru_cache(maxsize=16)
def _get_video_capture(video_path: str) -> cv2.VideoCapture:
    return cv2.VideoCapture(video_path)


_VIDEO_CAPTURE_LOCKS = collections.defaultdict(threading.Lock)


def read_video_mask_at(
    video_path: str,
    frame_index: int,
) -> np.ndarray | None:
    if frame_index < 0:
        return None
    cap = _get_video_capture(video_path)
    if not cap.isOpened():
        return None
    with _VIDEO_CAPTURE_LOCKS[video_path]:
        cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
        ret, frame = cap.read()
    if not ret:
        return None
    return frame[:, :, 2].astype(np.float32) / 255.0

