def __init__(self, path: str, asset_type: str) -> None:
    self.path = path
    self.type = asset_type

    if self.type == "sequence":
        try:
            # Use a generator with os.scandir for I/O and memory efficiency.
            # This avoids building a list and performing an unnecessary sort.
            self.frame_count = sum(1 for entry in os.scandir(self.path) 
                                   if entry.is_file() and is_image_file(entry.name))
        except (FileNotFoundError, NotADirectoryError):
            self.frame_count = 0
    elif self.type == "video":
        # The original approach is already the most efficient way to get frame
        # count from video metadata using OpenCV.
        try:
            cap = cv2.VideoCapture(self.path)
            if cap.isOpened():
                self.frame_count = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
            else:
                self.frame_count = 0
            cap.release()
        except cv2.error:
            self.frame_count = 0
    else:
        self.frame_count = 0

