import cv2
import numpy as np

logger = logging.getLogger(__name__)


class _ReleasingVideoCapture:
    """A wrapper for cv2.VideoCapture that calls release() on deletion."""

    def __init__(self, video_path: str):
        self._cap = cv2.VideoCapture(video_path)
        if not self._cap.isOpened():
            raise IOError(f"Could not open video file: {video_path}")

    def __getattr__(self, name):
        return getattr(self._cap, name)

    def __del__(self):
        self._cap.release()


@functools.lru_cache(maxsize=16)
def _get_video_capture(video_path: str) -> _ReleasingVideoCapture:
    """
    Returns a cached _ReleasingVideoCapture object for the given video path.
    Cache size is limited to prevent holding too many file handles open.
    """
    return _ReleasingVideoCapture(video_path)


def read_video_mask_at(
    video_path: str,
    frame_index: int,
) -> np.ndarray | None:
    """Read a single mask frame from a video by index, as float32 [H, W] [0, 1].

    Extracts the blue channel (index 2) from BGR, matching the convention
    used by alpha-channel video masks.

    Args:
        video_path: Path to video file.
        frame_index: Zero-based frame index.

    Returns:
        float32 array [H, W] in [0, 1], or None if seek/read fails.
    """
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    try:
        # Use a cached VideoCapture object to avoid repeated file opening costs.
        cap = _get_video_capture(video_path)
    except IOError as e:
        logger.warning(str(e))
        return None

    if not cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index):
        logger.warning(
            "Failed to seek to frame %d in video %s. The video may be "
            "corrupt or the format may not support precise seeking.",
            frame_index,
            video_path,
        )
        return None

    ret, frame = cap.read()
    if not ret:
        return None

    return frame[:, :, 2].astype(np.float32) / 255.0

